// resolveNodeName returns DDX_NODE_NAME env, or the system hostname.
func resolveNodeName() string {
	if n := os.Getenv("DDX_NODE_NAME"); n != "" {
		return n
	}
	if h, err := os.Hostname(); err == nil && h != "" {
		return h
