Description=DDx Server — AI agent execution and document management
After=network.target

[Service]
Type=simple
ExecStart={{.ExecPath}} server
WorkingDirectory={{.WorkDir}}
Restart=on-failure
RestartSec=5
StandardOutput=append:{{.LogPath}}
