package registry

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/DocumentDrivenDX/ddx/internal/registry/defaultplugin"
)

func BuiltinDDxCachePath() (string, error) {
	pkg, err := BuiltinRegistry().Find("ddx")
	if err != nil {
		return "", err
	}
	return PluginCacheDir(pkg.Name, pkg.Version), nil
}

func EnsureBuiltinDDxCache(cachePath string, force bool) error {
	if !force && BuiltinDDxCacheReady(cachePath) {
		return nil
	}
	if err := os.RemoveAll(cachePath); err != nil {
		return fmt.Errorf("clear baked-in ddx cache %s: %w", cachePath, err)
	}
	if err := os.MkdirAll(filepath.Dir(cachePath), 0o755); err != nil {
		return fmt.Errorf("create baked-in ddx cache root: %w", err)
	}
	if err := MaterializeFS(defaultplugin.FS(), cachePath); err != nil {
		return fmt.Errorf("materialize baked-in ddx cache: %w", err)
	}
	return nil
}

func BuiltinDDxCacheReady(cachePath string) bool {
	for _, rel := range []string{
		"package.yaml",
		filepath.Join("skills", "ddx", "SKILL.md"),
	} {
		info, err := os.Stat(filepath.Join(cachePath, rel))
		if err != nil || info.IsDir() {
			return false
		}
	}
	return true
}

}

func snapshotEnv(keys []string) envSnapshot {
	out := make(envSnapshot, len(keys))
	for _, key := range keys {
		value, ok := os.LookupEnv(key)
		out[key] = struct {
			value string
			ok    bool
		}{value: value, ok: ok}
	}
	return out
}

func restoreEnv(snapshot envSnapshot) {
	for key, item := range snapshot {
		if item.ok {
			_ = os.Setenv(key, item.value)
		} else {
			_ = os.Unsetenv(key)
		}
	}
}

// buildTestLibraryFixture creates a per-test bare git repository that mimics
// the upstream ddx library. The repo lives under t.TempDir() and is cleaned up
// automatically with the test.
func buildTestLibraryFixture(t *testing.T) string {
	t.Helper()

	_, filename, _, _ := runtime.Caller(0)
	cmdDir := filepath.Dir(filename)
	fixtureDir := filepath.Join(cmdDir, "..", "test", "fixtures", "ddx-library")
	fixtureDir, err := filepath.Abs(fixtureDir)
	require.NoError(t, err)

	root := t.TempDir()
	workingRepo := filepath.Join(root, ".test-library")
	bareRepo := filepath.Join(root, ".test-library.git")

	require.NoError(t, os.MkdirAll(workingRepo, 0o755))
	require.NoError(t, syncDirectory(fixtureDir, workingRepo))

	cmds := []struct {
		args []string
		dir  string
	}{
		{[]string{"git", "init", "-b", "master"}, workingRepo},
		{[]string{"git", "config", "user.email", "test@example.com"}, workingRepo},
		{[]string{"git", "config", "user.name", "Test User"}, workingRepo},
		{[]string{"git", "add", "."}, workingRepo},
		{[]string{"git", "commit", "--allow-empty", "-m", "Test fixture"}, workingRepo},
		{[]string{"git", "init", "--bare", bareRepo}, ""},
		{[]string{"git", "remote", "add", "origin", bareRepo}, workingRepo},
		{[]string{"git", "push", "origin", "master"}, workingRepo},
	}

	for _, c := range cmds {
		cmd := exec.Command(c.args[0], c.args[1:]...)
		if c.dir != "" {
			cmd.Dir = c.dir
		}
		cmd.Env = gitpkg.CleanEnv()
		output, err := cmd.CombinedOutput()
		require.NoErrorf(t, err, "failed to run %v\nOutput: %s", c.args, output)
	}

	return bareRepo
}

// syncDirectory copies files from src to dst, preserving directory structure
func syncDirectory(src, dst string) error {
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		// Skip .git directories from source
		if info.IsDir() && info.Name() == ".git" {
			return filepath.SkipDir
		}
